-- ===== 임플란트 추가 (29개) =====
INSERT OR IGNORE INTO dictionary (slug, term_ko, term_en, category, summary, description, related_treatment, related_terms, difficulty, is_featured) VALUES
('all-on-4', '올온포', 'All-on-4', '임플란트', '4개 임플란트로 전체 치아를 지지하는 방식', '무치악(치아가 모두 없는) 환자의 턱뼈에 4개의 임플란트를 전략적으로 배치하고, 그 위에 전체 보철물을 고정하는 술식입니다. 뒤쪽 2개는 비스듬히 식립하여 뼈이식 없이도 가능한 경우가 많아, 수술 부담과 비용을 줄일 수 있습니다.', 'implant', '임플란트,무치악,고정식 틀니', 3, 1),
('all-on-6', '올온식스', 'All-on-6', '임플란트', '6개 임플란트로 전체 치아를 지지하는 방식', 'All-on-4와 유사하지만 6개의 임플란트를 사용하여 더 강한 지지력을 제공합니다. 특히 윗턱처럼 뼈가 약한 부위에서 더 안정적이며, 장기적인 성공률이 높습니다.', 'implant', '올온포,임플란트,무치악', 3, 0),
('flapless-surgery', '무절개 임플란트', 'Flapless Implant Surgery', '임플란트', '잇몸을 절개하지 않는 임플란트 수술', '잇몸을 크게 절개하지 않고 작은 구멍만 뚫어 임플란트를 식립하는 최소 침습 수술법입니다. 출혈이 적고, 수술 후 부기와 통증이 현저히 줄어들며, 회복이 빠릅니다. 디지털 가이드와 함께 사용됩니다.', 'implant', '임플란트,디지털 가이드,최소침습', 3, 0),
('mini-implant', '미니 임플란트', 'Mini Implant', '임플란트', '직경이 작은 소형 임플란트', '일반 임플란트보다 직경이 작은(1.8~2.9mm) 임플란트입니다. 뼈가 매우 얇은 부위나 틀니 고정용으로 사용되며, 교정 시 고정원으로도 활용됩니다.', 'implant', '임플란트,틀니,교정', 2, 0),
('loading-protocol', '임플란트 로딩', 'Loading Protocol', '임플란트', '임플란트에 보철물을 장착하는 시기', '임플란트 식립 후 보철물을 얹는 시기에 따라 즉시 로딩(당일), 조기 로딩(2~6주), 지연 로딩(3~6개월)으로 나뉩니다. 환자의 뼈 상태와 식립 안정성에 따라 결정됩니다.', 'implant', '임플란트,골유착,보철', 3, 0),
('implant-bridge', '임플란트 브릿지', 'Implant-Supported Bridge', '임플란트', '임플란트로 지지하는 연결 보철물', '2개 이상의 임플란트를 식립하고 그 사이를 연결하는 보철물입니다. 여러 개의 치아가 연속으로 없을 때, 모든 자리에 임플란트를 하지 않아도 되어 비용과 수술 부담을 줄일 수 있습니다.', 'implant', '임플란트,브릿지,보철', 2, 0),
('straumann', '스트라우만', 'Straumann', '임플란트', '스위스 프리미엄 임플란트 시스템', '1954년 설립된 세계적 스위스 임플란트 브랜드입니다. SLActive 표면처리 기술로 빠른 골유착이 가능하며, 임상 데이터가 풍부하여 안정성이 검증된 프리미엄 시스템입니다.', 'implant', '임플란트,골유착,프리미엄', 2, 0),
('osstem', '오스템', 'Osstem', '임플란트', '국내 1위 임플란트 시스템', '대한민국 최대 임플란트 제조사로, 전 세계 70여 개국에 수출하는 글로벌 브랜드입니다. SA 표면처리와 다양한 라인업을 보유하여 환자 상황에 맞는 최적의 선택이 가능합니다.', 'implant', '임플란트,국산,골유착', 2, 0),
('dentium', '덴티움', 'Dentium', '임플란트', '한국 프리미엄 임플란트 시스템', '국내 개발 임플란트 시스템으로, SLA 표면처리 기술과 독자적 디자인으로 글로벌 시장에서 인정받고 있습니다. 다양한 적응증에 활용 가능한 폭넓은 제품 라인업을 보유하고 있습니다.', 'implant', '임플란트,국산,골유착', 2, 0),
('cbct', '3D CT (CBCT)', 'Cone Beam Computed Tomography', '임플란트', '치과용 3차원 컴퓨터 단층촬영', '원뿔형 X선을 이용해 턱뼈와 치아의 3D 영상을 촬영하는 장비입니다. 임플란트 수술 전 뼈의 양, 두께, 신경 위치 등을 정밀 분석하여 안전한 수술 계획을 수립합니다.', 'implant', '임플란트,디지털 가이드,진단', 2, 1),
('ridge-augmentation', '치조골 증대술', 'Ridge Augmentation', '임플란트', '좁아진 치조골을 넓히는 수술', '발치 후 자연적으로 좁아진 치조골(잇몸뼈)의 폭과 높이를 인공뼈 이식재로 보충하는 수술입니다. 임플란트를 안전하게 식립하기 위한 충분한 뼈 볼륨을 확보합니다.', 'bone-graft', '뼈이식,치조골,임플란트', 3, 0),
('cover-screw', '커버 스크루', 'Cover Screw', '임플란트', '골유착 기간 중 픽스쳐를 보호하는 나사', '임플란트 식립 후 픽스쳐 상부에 체결하는 작은 나사입니다. 골유착 기간 동안 조직이 픽스쳐 내부로 자라 들어오는 것을 방지하고, 픽스쳐를 보호합니다.', 'implant', '픽스쳐,골유착,힐링 어버트먼트', 3, 0),
('implant-failure', '임플란트 실패', 'Implant Failure', '임플란트', '임플란트가 탈락하거나 기능하지 못하는 상태', '골유착 실패, 감염, 과부하, 전신 질환 등으로 임플란트가 흔들리거나 빠지는 경우입니다. 흡연, 조절되지 않는 당뇨, 부적절한 관리 등이 위험 요소입니다. 재식립이 가능합니다.', 'implant', '골유착,임플란트 주위염,뼈이식', 2, 0),
('xenograft', '이종골', 'Xenograft', '임플란트', '동물 유래 뼈이식재', '소나 돼지 등 동물의 뼈를 특수 처리하여 만든 뼈이식 재료입니다. 항원성을 제거하고 무기질 성분만 남겨 안전하게 사용합니다. Bio-Oss가 대표적인 제품입니다.', 'bone-graft', '뼈이식,자가골,합성골', 3, 0),
('autograft', '자가골', 'Autograft', '임플란트', '본인의 뼈를 이용한 이식', '환자 자신의 턱뼈나 다른 부위에서 채취한 뼈를 이식하는 방법입니다. 거부반응이 없고 뼈 형성 능력이 가장 우수하지만, 채취 부위에 추가 수술이 필요합니다.', 'bone-graft', '뼈이식,이종골,합성골', 3, 0),
('synthetic-bone', '합성골', 'Synthetic Bone Graft', '임플란트', '인공적으로 만든 뼈이식재', '화학적으로 합성된 뼈이식 재료로, 하이드록시아파타이트(HA), 트리칼슘포스페이트(TCP) 등이 있습니다. 채취 수술이 불필요하고, 감염 위험이 없는 장점이 있습니다.', 'bone-graft', '뼈이식,자가골,이종골', 3, 0),
('prp', 'PRP', 'Platelet-Rich Plasma', '임플란트', '자가 혈소판 농축 혈장', '환자의 혈액에서 혈소판을 농축 추출한 것으로, 성장인자가 풍부하여 수술 부위의 조직 재생과 치유를 촉진합니다. 뼈이식이나 임플란트 수술 시 사용됩니다.', 'bone-graft', '뼈이식,성장인자,재생', 3, 0),
('implant-insurance', '임플란트 보험', 'Implant Insurance Coverage', '임플란트', '건강보험이 적용되는 임플란트', '만 65세 이상 어르신은 건강보험 혜택으로 평생 2개까지 임플란트를 저렴하게 받을 수 있습니다. 본인부담금은 약 30%(약 50~70만원 수준)이며, 골이식도 일부 급여 적용됩니다.', 'implant', '임플란트,건강보험,노인', 1, 1),
('nerve-damage', '신경 손상', 'Nerve Damage', '임플란트', '임플란트 수술 시 발생할 수 있는 합병증', '하악(아래턱) 임플란트 수술 시 하치조신경에 손상이 발생할 수 있습니다. 입술이나 턱의 감각 이상이 나타나며, 3D CT 정밀 분석과 디지털 가이드를 통해 예방합니다.', 'implant', '임플란트,3D CT,디지털 가이드', 2, 0),
('socket-preservation', '발치와 보존술', 'Socket Preservation', '임플란트', '발치 후 뼈 흡수를 방지하는 시술', '치아를 뽑은 직후 빈 구멍에 뼈이식재를 채워 치조골이 자연적으로 녹아내리는 것을 방지하는 시술입니다. 향후 임플란트 식립 시 뼈이식 필요성을 줄여줍니다.', 'implant', '뼈이식,발치,치조골', 2, 0),
('temporary-prosthesis', '임시 보철물', 'Temporary Prosthesis', '임플란트', '골유착 기간 중 사용하는 임시 치아', '임플란트 골유착을 기다리는 동안 심미성과 기능을 유지하기 위해 착용하는 임시 치아입니다. 레진으로 제작되며, 최종 보철 장착 시 제거됩니다.', 'implant', '임플란트,보철,골유착', 2, 0),
('smoking-implant', '흡연과 임플란트', 'Smoking and Implants', '임플란트', '흡연이 임플란트에 미치는 영향', '흡연은 임플란트 실패율을 2~3배 높입니다. 니코틴이 혈관을 수축시켜 잇몸 혈류를 감소시키고, 골유착을 방해합니다. 수술 전후 최소 2주간 금연이 강력히 권고됩니다.', 'implant', '임플란트,골유착,실패', 1, 0),
('implant-maintenance', '임플란트 유지관리', 'Implant Maintenance', '임플란트', '임플란트 장기 관리 방법', '임플란트는 자연치아와 달리 신경이 없어 문제를 느끼기 어렵습니다. 6개월마다 정기 검진, 전문 세정(워터픽, 치간 칫솔 활용), 연 1회 X-ray 촬영이 권장됩니다.', 'implant', '임플란트,주위염,스케일링', 1, 0),
('full-mouth-rehab', '전악 재건', 'Full Mouth Rehabilitation', '임플란트', '전체 구강을 종합적으로 복원하는 치료', '심한 치아 손실이나 마모로 기능과 심미성이 크게 저하된 경우, 임플란트, 보철, 교정 등을 종합적으로 계획하여 전체 구강을 복원하는 대규모 치료입니다.', 'implant', '임플란트,보철,교정,올온포', 3, 0),
('guided-surgery', '가이드 수술', 'Guided Surgery', '임플란트', '디지털 가이드를 이용한 정밀 수술', '3D CT, 구강 스캔 데이터를 기반으로 컴퓨터에서 수술을 미리 계획하고, 3D 프린팅된 가이드를 이용해 정확한 위치에 임플란트를 식립하는 방법입니다.', 'implant', '디지털 가이드,3D CT,무절개', 2, 0),
('one-day-implant', '원데이 임플란트', 'One-Day Implant', '임플란트', '하루 만에 완성하는 임플란트', '발치, 임플란트 식립, 임시 치아 장착까지 하루에 모두 진행하는 시술법입니다. 모든 환자에게 적용 가능하지는 않으며, 뼈 상태와 구강 조건이 충분할 때 시행합니다.', 'implant', '즉시 임플란트,임시 보철물', 2, 0),
('implant-cost-factor', '임플란트 가격 결정 요인', 'Implant Cost Factors', '임플란트', '임플란트 비용에 영향을 미치는 요소들', '임플란트 비용은 브랜드(국산/외산), 보철 소재(지르코니아/PFM), 뼈이식 필요 여부, 수술 난이도, 진료의 전문성 등에 따라 달라집니다. 보험 적용 여부도 중요한 요소입니다.', 'implant', '임플란트,임플란트 보험,보철', 1, 0),
('diabetes-implant', '당뇨와 임플란트', 'Diabetes and Implants', '임플란트', '당뇨 환자의 임플란트 시술 고려사항', '당뇨는 혈당 조절이 잘 되면(HbA1c 7% 이하) 임플란트 시술이 가능합니다. 다만 상처 치유가 느리고 감염 위험이 높아, 혈당 관리와 주기적 검진이 더욱 중요합니다.', 'implant', '임플란트,전신질환,골유착', 2, 0),
('osteoporosis-implant', '골다공증과 임플란트', 'Osteoporosis and Implants', '임플란트', '골다공증 환자의 임플란트 시술 고려사항', '골다공증 자체는 임플란트의 절대적 금기증이 아닙니다. 다만 비스포스포네이트 약물 복용 이력이 있는 경우, 턱뼈 괴사(MRONJ) 위험이 있어 약물 복용 기간과 종류를 반드시 확인해야 합니다.', 'implant', '임플란트,전신질환,뼈이식', 3, 0);

-- ===== 교정 추가 (16개) =====
INSERT OR IGNORE INTO dictionary (slug, term_ko, term_en, category, summary, description, related_treatment, related_terms, difficulty, is_featured) VALUES
('ceramic-bracket', '세라믹 브라켓', 'Ceramic Bracket', '교정', '치아색 세라믹 소재 교정 장치', '금속 브라켓과 동일한 원리이지만, 치아색 세라믹으로 제작되어 눈에 덜 띕니다. 심미성이 좋아 성인 교정 환자에게 인기가 있습니다.', 'invisalign', '브라켓,교정,심미', 1, 0),
('lingual-orthodontics', '설측교정', 'Lingual Orthodontics', '교정', '치아 안쪽에 부착하는 교정', '브라켓을 치아 바깥이 아닌 안쪽(혀 쪽)에 부착하는 교정 방법입니다. 정면에서 보이지 않아 심미성이 뛰어나지만, 기술적으로 어렵고 비용이 높습니다.', 'invisalign', '교정,브라켓,심미', 2, 0),
('self-ligating', '자가결찰 브라켓', 'Self-Ligating Bracket', '교정', '와이어를 자체 고정하는 교정 장치', '별도의 고무줄이나 결찰 와이어 없이 브라켓 자체의 뚜껑으로 와이어를 고정하는 장치입니다. 마찰이 적어 치아 이동이 부드럽고, 내원 간격을 늘릴 수 있습니다. 데이몬 브라켓이 대표적입니다.', 'invisalign', '브라켓,와이어,교정', 2, 0),
('elastics', '교정용 고무줄', 'Orthodontic Elastics', '교정', '교합 조정에 사용하는 탄성 고무줄', '교정 치료 중 윗니와 아랫니 사이에 걸어 교합을 맞추는 작은 고무줄입니다. 환자가 직접 착탈하며, 착용 시간을 잘 지켜야 치료 효과가 좋습니다.', 'invisalign', '교정,교합,부정교합', 1, 0),
('power-chain', '파워체인', 'Power Chain', '교정', '치아 사이 공간을 닫는 연결 고무', '연속된 고리 형태의 탄성 체인으로, 발치 후 생긴 공간을 닫거나 치아 사이 간격을 모을 때 사용합니다. 브라켓에 연결하여 지속적인 힘을 가합니다.', 'invisalign', '교정,브라켓,발치교정', 2, 0),
('orthognathic', '악교정 수술', 'Orthognathic Surgery', '교정', '턱뼈를 이동시키는 교정 수술', '교정만으로 해결할 수 없는 심한 골격성 부정교합(주걱턱, 무턱 등)을 턱뼈 자체를 절골하여 이동시키는 수술입니다. 교정과와 구강외과가 협진합니다.', NULL, '교정,부정교합,구강외과', 3, 0),
('attachment', '어태치먼트', 'Attachment', '교정', '인비절라인 치아 이동 보조 돌기', '인비절라인 교정 시 치아 표면에 부착하는 작은 레진 돌기입니다. 얼라이너가 치아에 더 정확한 힘을 가할 수 있도록 돕는 역할을 하며, 교정 완료 후 제거합니다.', 'invisalign', '인비절라인,얼라이너,레진', 2, 0),
('ipr', 'IPR', 'Interproximal Reduction', '교정', '치아 사이 미세 삭제', '인접한 치아 사이의 법랑질을 0.1~0.5mm 정도 미세하게 삭제하여 공간을 확보하는 방법입니다. 발치 대신 치아 정렬 공간을 만들 때 활용되며, 치아 건강에 영향을 주지 않습니다.', 'invisalign', '인비절라인,교정,법랑질', 2, 0),
('expander', '급속 확장 장치', 'Rapid Palatal Expander', '교정', '윗턱을 넓히는 장치', '성장기 아동·청소년의 좁은 윗턱뼈를 넓혀 치아 배열 공간을 확보하는 장치입니다. 구개 봉합이 완전히 닫히기 전(보통 15세 이전)에 사용하면 효과적입니다.', 'invisalign', '교정,소아교정,부정교합', 2, 0),
('space-maintainer', '공간 유지 장치', 'Space Maintainer', '교정', '유치 조기 탈락 시 공간을 유지하는 장치', '유치가 정상 시기보다 일찍 빠졌을 때, 영구치가 나올 공간을 확보하기 위해 장착하는 장치입니다. 인접 치아가 빈 공간으로 기울어지는 것을 방지합니다.', NULL, '소아치과,유치,교정', 1, 0),
('class-1', '1급 부정교합', 'Class I Malocclusion', '교정', '위아래 턱 관계는 정상이나 치아 배열이 불량한 상태', '앞니 관계(어금니 교합)는 정상이지만, 치아들이 삐뚤어지거나 겹쳐 있는 경우입니다. 교정만으로 비교적 쉽게 해결 가능한 유형입니다.', 'invisalign', '부정교합,교정,총생', 2, 0),
('class-2', '2급 부정교합', 'Class II Malocclusion', '교정', '윗턱이 돌출된 부정교합', '윗니가 아랫니보다 과도하게 앞으로 나온 상태(소위 "벅치")입니다. 윗턱 전돌, 아랫턱 후퇴, 또는 둘 다의 조합으로 발생합니다. 심한 경우 악교정 수술이 필요합니다.', 'invisalign', '부정교합,교정,과개교합', 2, 0),
('class-3', '3급 부정교합', 'Class III Malocclusion', '교정', '아랫턱이 돌출된 부정교합 (주걱턱)', '아랫니가 윗니보다 앞으로 나온 상태입니다. 아랫턱 전돌(주걱턱) 또는 윗턱 열성장이 원인이며, 반대교합을 동반합니다. 성인은 악교정 수술이 필요할 수 있습니다.', 'invisalign', '부정교합,반대교합,악교정 수술', 2, 0),
('anchorage', '교정 고정원', 'Anchorage', '교정', '치아를 이동시킬 때 고정점 역할을 하는 것', '교정에서 치아를 원하는 방향으로 이동시키려면 반대편에 고정점이 필요합니다. 미니 스크루(미니 임플란트), 어금니, 교정 장치 등이 고정원으로 사용됩니다.', 'invisalign', '미니 임플란트,교정,TAD', 3, 0),
('tad', 'TAD (미니 스크루)', 'Temporary Anchorage Device', '교정', '교정용 임시 고정 나사', '교정 치료 시 턱뼈에 삽입하는 작은 나사(지름 1.2~2mm)입니다. 절대 고정원 역할을 하여 치아를 효과적으로 이동시킵니다. 교정 완료 후 간단히 제거됩니다.', 'invisalign', '교정,고정원,미니 임플란트', 2, 0),
('orthodontic-wax', '교정용 왁스', 'Orthodontic Wax', '교정', '브라켓으로 인한 점막 자극을 완화하는 왁스', '브라켓이나 와이어가 입안 점막을 찔러 불편할 때 바르는 의료용 왁스입니다. 장치 위에 떼어 붙이면 부드러운 보호막이 형성되어 통증을 줄여줍니다.', 'invisalign', '브라켓,교정,구내염', 1, 0);

-- ===== 보철/심미 추가 (15개) =====
INSERT OR IGNORE INTO dictionary (slug, term_ko, term_en, category, summary, description, related_treatment, related_terms, difficulty, is_featured) VALUES
('bridge', '브릿지', 'Bridge', '보철', '양쪽 치아를 이용해 빈 자리를 메우는 보철물', '빠진 치아 양옆의 건강한 치아를 깎아 기둥으로 삼고, 그 위에 연결된 보철물을 씌우는 방법입니다. 임플란트가 어려운 경우의 대안이지만, 양쪽 치아를 삭제해야 하는 단점이 있습니다.', 'crown', '크라운,보철,임플란트', 1, 0),
('maryland-bridge', '메릴랜드 브릿지', 'Maryland Bridge', '보철', '최소 삭제로 부착하는 접착식 브릿지', '양쪽 치아를 많이 깎지 않고, 금속 날개로 접착하여 고정하는 보존적 브릿지입니다. 주로 앞니 1개가 빠진 경우에 사용되며, 치아 삭제량이 적습니다.', 'crown', '브릿지,보철,접착', 2, 0),
('temporary-crown', '임시 크라운', 'Temporary Crown', '보철', '최종 보철물 완성 전 사용하는 임시 치아', '본뜨기 후 최종 크라운이 만들어지는 1~2주 동안 착용하는 플라스틱 재질의 임시 보철물입니다. 심미성과 기능을 유지하고, 삭제된 치아를 보호합니다.', 'crown', '크라운,보철', 1, 0),
('cad-cam', 'CAD/CAM', 'Computer-Aided Design/Manufacturing', '보철', '컴퓨터 설계·제작 디지털 보철 기술', '컴퓨터로 보철물을 3D 설계(CAD)하고, 밀링 기계로 자동 가공(CAM)하는 디지털 보철 제작 기술입니다. CEREC 시스템이 대표적이며, 정밀도와 적합도가 뛰어납니다.', 'cerec', 'CEREC,디지털,밀링', 2, 0),
('dental-milling', '밀링', 'Dental Milling', '보철', '세라믹 블록을 깎아 보철물을 만드는 과정', 'CAD/CAM 시스템에서 설계된 데이터에 따라 세라믹이나 지르코니아 블록을 다이아몬드 버로 정밀 깎아 보철물을 제작하는 과정입니다. CEREC 밀링은 약 15분이 소요됩니다.', 'cerec', 'CEREC,CAD/CAM,세라믹', 2, 0),
('primescan', 'PrimeScan', 'PrimeScan', '보철', 'CEREC용 최신 구강 스캐너', 'Dentsply Sirona의 최신 구강 스캐너로, 기존 본뜨기 대신 디지털 스캔으로 정밀한 3D 데이터를 획득합니다. CEREC 시스템과 연동하여 당일 보철 제작의 시작점입니다.', 'cerec', 'CEREC,디지털,구강 스캔', 2, 0),
('sintering', '소성', 'Sintering', '보철', 'CEREC 보철의 최종 강화 과정', '밀링 된 세라믹 보철물을 고온(약 800~900°C)에서 구워 강도와 색상을 완성하는 최종 과정입니다. 소성 후 자연치아와 유사한 색감과 광택이 나타납니다.', 'cerec', 'CEREC,밀링,세라믹', 3, 0),
('post-core', '포스트 코어', 'Post and Core', '보철', '신경치료 후 크라운을 지지하는 기둥', '신경치료 후 남은 치아 구조가 부족할 때, 뿌리 관에 기둥(포스트)을 세우고 그 위에 코어(토대)를 만들어 크라운이 안정적으로 올라갈 수 있게 하는 시술입니다.', 'crown', '신경치료,크라운,보철', 2, 0),
('denture', '틀니', 'Denture', '보철', '탈착 가능한 인공 치아 장치', '여러 개 또는 전체 치아가 없을 때 사용하는 탈착식 보철물입니다. 부분 틀니와 완전 틀니가 있으며, 잇몸과 남은 치아에 의존하여 고정됩니다.', NULL, '보철,임플란트 오버덴처', 1, 0),
('partial-denture', '부분 틀니', 'Partial Denture', '보철', '일부 치아가 없을 때 사용하는 틀니', '여러 개의 치아가 빠졌지만 일부 치아는 남아있을 때 사용하는 틀니입니다. 남은 치아에 걸쇠(클라스프)로 고정하며, 식사 시 뺐다 끼웁니다.', NULL, '틀니,보철,클라스프', 1, 0),
('complete-denture', '완전 틀니', 'Complete Denture', '보철', '치아가 모두 없을 때 사용하는 틀니', '한쪽 턱의 치아가 모두 없을 때 사용하는 전체 틀니입니다. 잇몸 위에 올려놓는 방식으로, 흡착력으로 유지됩니다. 적응 기간이 필요합니다.', NULL, '틀니,임플란트 오버덴처,무치악', 1, 0),
('tooth-whitening', '치아 미백', 'Tooth Whitening', '보철', '치아를 하얗게 만드는 시술', '과산화수소나 카바마이드 퍼옥사이드 성분의 약제를 사용하여 치아의 색상을 밝게 하는 시술입니다. 전문가 미백(in-office)과 자가 미백(home bleaching) 두 가지가 있습니다.', 'whitening', '심미,과산화수소,미백', 1, 1),
('tooth-bonding', '본딩', 'Dental Bonding', '보철', '레진으로 치아 모양을 수복하는 시술', '치아색 복합레진을 직접 치아에 붙여 깨진 부분, 틈, 변색 등을 수복하는 시술입니다. 라미네이트보다 보존적이고 비용이 저렴하지만, 내구성은 상대적으로 낮습니다.', 'resin', '레진,심미,라미네이트', 1, 0),
('smile-design', '스마일 디자인', 'Digital Smile Design', '보철', '디지털 기술로 이상적인 미소를 설계하는 기법', '환자의 얼굴 비율, 입술 라인, 치아 비율 등을 디지털로 분석하여 최적의 미소를 설계하는 심미 치과의 첨단 기법입니다. 시술 전 최종 결과를 미리 확인할 수 있습니다.', 'cosmetic', '라미네이트,심미보철,디지털', 2, 0),
('gum-contouring', '잇몸 성형', 'Gum Contouring', '보철', '잇몸 라인을 다듬어 심미성을 개선하는 시술', '잇몸이 과도하게 보이거나(거미 스마일) 비대칭인 경우, 레이저나 전기 메스로 잇몸 라인을 다듬는 시술입니다. 라미네이트나 크라운과 함께 시행하면 효과적입니다.', 'cosmetic', '심미,잇몸,레이저', 2, 0);

-- ===== 일반/보존 추가 (15개) =====
INSERT OR IGNORE INTO dictionary (slug, term_ko, term_en, category, summary, description, related_treatment, related_terms, difficulty, is_featured) VALUES
('dental-caries', '충치 (치아우식증)', 'Dental Caries', '일반', '세균에 의해 치아가 썩는 질환', '구강 내 세균이 음식물의 당분을 분해하면서 산을 만들고, 이 산이 치아의 법랑질과 상아질을 녹여 구멍을 만드는 질환입니다. 초기에는 통증이 없어 정기 검진이 중요합니다.', 'cavity', '법랑질,상아질,레진', 1, 1),
('composite-resin', '복합 레진', 'Composite Resin', '일반', '치아색 충전 재료', '충치를 제거한 후 빈 공간을 메우는 치아색 플라스틱 재료입니다. 빛을 쬐어 굳히며(광중합), 색상을 치아에 맞출 수 있어 자연스럽습니다. 당일 치료가 가능합니다.', 'resin', '충치,레진,광중합', 1, 0),
('root-canal-treatment', '신경치료 (근관치료)', 'Root Canal Treatment', '일반', '감염된 치아 신경을 제거하는 치료', '충치가 깊어 치아 신경(치수)까지 감염되었을 때, 감염된 신경을 제거하고 소독한 후 근관을 밀봉하는 치료입니다. 통증이 심하지만 치료 후 치아를 보존할 수 있습니다.', 'root-canal', '충치,신경,크라운', 1, 1),
('dental-pulp', '치수 (치아 신경)', 'Dental Pulp', '일반', '치아 내부의 신경과 혈관 조직', '치아 중심부에 있는 연조직으로, 신경, 혈관, 결합조직으로 구성됩니다. 치아에 영양을 공급하고 온도/압력을 감지합니다. 충치가 치수까지 도달하면 극심한 통증이 발생합니다.', 'root-canal', '신경치료,충치,치아', 2, 0),
('pulpitis', '치수염', 'Pulpitis', '일반', '치아 신경에 염증이 생긴 상태', '충치, 외상, 금이 간 치아 등으로 치수에 세균이 감염되어 염증이 발생한 상태입니다. 가역성(치료 시 회복 가능)과 비가역성(신경치료 필요)으로 나뉩니다.', 'root-canal', '치수,신경치료,충치', 2, 0),
('dental-abscess', '치근단 농양', 'Dental Abscess', '일반', '치아 뿌리 끝에 고름이 찬 상태', '치수 감염이 치아 뿌리 끝까지 진행되어 고름 주머니가 형성된 상태입니다. 심한 통증, 부기, 열감이 동반되며, 신경치료 또는 발치가 필요합니다.', 'root-canal', '신경치료,감염,발치', 2, 0),
('gutta-percha', '거타퍼차', 'Gutta-Percha', '일반', '근관 충전에 사용하는 고무 재료', '신경치료 후 비어있는 근관(신경관)을 메우는 데 사용하는 열가소성 고무 재료입니다. 열이나 압력으로 변형하여 근관 내부를 빈틈없이 채우고 밀봉합니다.', 'root-canal', '신경치료,근관,충전', 3, 0),
('fluoride', '불소', 'Fluoride', '일반', '치아 강화에 사용하는 화학 성분', '치아 법랑질을 강화하고, 초기 충치의 재광화를 촉진하며, 세균의 산 생성을 억제하는 성분입니다. 불소 도포, 불소 치약, 불소 양치액 등의 형태로 사용됩니다.', NULL, '충치 예방,법랑질,재광화', 1, 0),
('sealant', '실란트 (치아 홈 메우기)', 'Dental Sealant', '일반', '어금니 홈을 메워 충치를 예방하는 시술', '어금니의 깊은 홈(소와/열구)을 레진 재료로 메워 음식물과 세균이 끼는 것을 방지하는 예방 치료입니다. 주로 영구치가 나온 직후 아동에게 시행하며, 보험 적용됩니다.', NULL, '충치 예방,어금니,소아', 1, 1),
('amalgam', '아말감', 'Amalgam', '일반', '은합금 충전 재료', '수은, 은, 주석, 구리 등을 합금한 전통적인 충전 재료입니다. 강도가 높고 비용이 저렴하지만, 은색이 눈에 띄고 수은 논란이 있어 현재는 레진이 더 선호됩니다.', 'cavity', '충치,충전,레진', 2, 0),
('glass-ionomer', '글래스 아이오노머', 'Glass Ionomer', '일반', '불소를 방출하는 충전 재료', '유리 분말과 산의 반응으로 경화되는 충전 재료입니다. 지속적으로 불소를 방출하여 2차 충치를 예방하며, 접착력이 좋습니다. 주로 유치 충전이나 치경부 충치에 사용됩니다.', 'cavity', '충전,불소,유치', 2, 0),
('bruxism', '이갈이', 'Bruxism', '일반', '수면 중 또는 낮에 이를 가는 습관', '수면 중(야간 이갈이) 또는 깨어있을 때(주간 이악물기) 치아를 강하게 갈거나 악무는 습관입니다. 치아 마모, 턱관절 장애, 두통 등을 유발하며, 나이트 가드로 관리합니다.', NULL, '턱관절,마모,나이트 가드', 1, 0),
('nightguard', '나이트 가드', 'Night Guard', '일반', '이갈이 방지용 보호 장치', '수면 중 이갈이로부터 치아를 보호하기 위해 착용하는 맞춤형 투명 장치입니다. 치아 마모, 턱관절 통증, 보철물 파손 등을 예방합니다. 상악(윗턱)에 착용하는 것이 일반적입니다.', NULL, '이갈이,턱관절,보호', 1, 0),
('tooth-sensitivity', '시린이 (지각과민)', 'Tooth Sensitivity', '일반', '차가운 것에 치아가 시린 증상', '잇몸 퇴축이나 법랑질 마모로 상아질이 노출되면, 차가운/뜨거운/단 음식에 찌릿한 통증이 느껴집니다. 지각과민 치약, 불소 도포, 레진 코팅 등으로 치료합니다.', NULL, '잇몸 퇴축,상아질,법랑질', 1, 0),
('dry-socket', '건성 발치와', 'Dry Socket (Alveolar Osteitis)', '일반', '발치 후 혈병이 빠져 뼈가 노출된 상태', '발치 후 생긴 혈병(피딱지)이 조기에 탈락하거나 형성되지 않아 발치 부위의 뼈가 노출되는 합병증입니다. 극심한 통증이 2~5일째부터 나타나며, 드레싱 치료가 필요합니다.', NULL, '발치,통증,합병증', 2, 0);

-- ===== 외과 추가 (10개) =====
INSERT OR IGNORE INTO dictionary (slug, term_ko, term_en, category, summary, description, related_treatment, related_terms, difficulty, is_featured) VALUES
('wisdom-tooth-extraction', '사랑니 발치', 'Wisdom Tooth Extraction', '외과', '사랑니를 뽑는 수술', '제3대구치(사랑니)를 제거하는 수술입니다. 매복(뼈 속에 묻힌), 수평 매복, 부분 맹출 등 상태에 따라 수술 난이도가 달라집니다. 구강외과 전문의가 시행하면 안전합니다.', 'wisdom-tooth', '사랑니,매복치,구강외과', 1, 1),
('local-anesthesia', '국소마취', 'Local Anesthesia', '외과', '치료 부위만 마비시키는 마취', '치과 치료 시 치료할 부위의 신경만 마비시켜 통증을 차단하는 방법입니다. 의식은 유지되며, 마취 효과는 2~4시간 지속됩니다. 리도카인이 대표적인 마취제입니다.', NULL, '마취,통증,리도카인', 1, 0),
('conscious-sedation', '수면 마취 (의식 하 진정)', 'Conscious Sedation', '외과', '불안을 줄이는 가벼운 진정 마취', '정맥 주사나 흡입을 통해 환자의 불안감을 줄이고 편안한 상태에서 치료하는 방법입니다. 완전히 잠드는 것은 아니며, 호흡은 유지됩니다. 치과 공포증이 심한 환자에게 유용합니다.', NULL, '마취,치과 공포증,정맥', 2, 0),
('biopsy', '조직 검사', 'Biopsy', '외과', '구강 내 이상 조직의 일부를 채취하여 검사', '구강 내 종양, 궤양, 백반증 등 이상 소견이 있을 때 조직 일부를 떼어 현미경으로 검사하는 것입니다. 양성/악성 여부를 확인하여 적절한 치료 방향을 결정합니다.', NULL, '구강암,백반증,병리검사', 3, 0),
('frenectomy', '소대 절제술', 'Frenectomy', '외과', '입술이나 혀의 소대를 절제하는 수술', '입술 안쪽(순소대)이나 혀 아래(설소대)의 근육 띠가 짧거나 두꺼워 기능 장애를 일으킬 때 절제하는 수술입니다. 발음 장애, 치간 이개, 틀니 불안정 등을 개선합니다.', NULL, '설소대,발음,소아', 2, 0),
('apicoectomy', '치근단 절제술', 'Apicoectomy', '외과', '치아 뿌리 끝을 잘라내는 수술', '신경치료 후에도 치아 뿌리 끝(치근단)의 감염이 해결되지 않을 때, 잇몸을 열고 감염된 뿌리 끝 부분을 외과적으로 절제하는 수술입니다. 치아를 보존하기 위한 최후의 방법입니다.', 'root-canal', '신경치료,치근단 농양,수술', 3, 0),
('tooth-reimplantation', '재식술', 'Tooth Reimplantation', '외과', '빠진 치아를 다시 심는 시술', '외상으로 완전히 빠진 치아를 원래 위치에 다시 심는 시술입니다. 빠진 후 30분~1시간 이내에 시행하면 성공률이 높습니다. 치아를 우유나 식염수에 보관하여 내원해야 합니다.', NULL, '외상,응급,치아 보존', 2, 0),
('incision-drainage', '절개 배농', 'Incision and Drainage', '외과', '고름을 절개하여 배출하는 응급 처치', '구강 내 농양(고름 주머니)이 형성되었을 때, 절개하여 고름을 배출하고 감염을 조절하는 응급 처치입니다. 통증과 부기를 빠르게 완화시킵니다.', NULL, '농양,감염,응급', 2, 0),
('hemostasis', '지혈', 'Hemostasis', '외과', '출혈을 멈추게 하는 처치', '발치나 수술 후 출혈을 멈추게 하는 처치입니다. 거즈 압박, 봉합, 지혈제(Surgicel, Gelfoam) 사용 등 다양한 방법이 있습니다. 항응고제 복용 환자는 사전 관리가 중요합니다.', NULL, '발치,수술,출혈', 2, 0),
('suture', '봉합', 'Suture', '외과', '수술 부위를 실로 꿰매는 것', '발치나 잇몸 수술 후 절개 부위를 의료용 실로 꿰매어 상처 치유를 돕는 것입니다. 흡수성(저절로 녹는) 봉합사와 비흡수성(제거 필요) 봉합사가 있습니다.', NULL, '수술,발치,치유', 1, 0);

-- ===== 치주 추가 (8개) =====
INSERT OR IGNORE INTO dictionary (slug, term_ko, term_en, category, summary, description, related_treatment, related_terms, difficulty, is_featured) VALUES
('scaling', '스케일링', 'Dental Scaling', '치주', '치석을 제거하는 치료', '초음파 기구를 이용하여 치아 표면과 잇몸 사이에 쌓인 치석(석회화된 치태)을 제거하는 치료입니다. 연 1회 건강보험 적용되며, 잇몸 건강 유지의 기본입니다.', 'scaling', '치석,치태,잇몸', 1, 1),
('root-planing', '치근 활택술', 'Root Planing', '치주', '치아 뿌리 표면을 매끄럽게 다듬는 치료', '잇몸 아래 치아 뿌리 표면에 붙은 치석과 감염 조직을 제거하고, 뿌리를 매끄럽게 다듬어 세균이 재부착하기 어렵게 만드는 치료입니다. 깊은 치주낭에 시행합니다.', 'scaling', '치석,치주낭,잇몸', 2, 0),
('periodontal-surgery', '치주 수술', 'Periodontal Surgery', '치주', '진행된 치주질환을 수술적으로 치료', '스케일링만으로 해결되지 않는 깊은 치주낭이나 심한 뼈 손실이 있을 때, 잇몸을 열고 직접 깊은 곳의 치석과 감염 조직을 제거하는 수술입니다.', 'scaling', '잇몸,치주낭,뼈 손실', 3, 0),
('gum-graft', '잇몸 이식술', 'Gum Graft', '치주', '퇴축된 잇몸을 보충하는 수술', '잇몸이 심하게 내려가(퇴축) 치아 뿌리가 노출된 경우, 구개(입천장)에서 잇몸 조직을 채취하여 이식하는 수술입니다. 심미성과 치아 보호 효과가 있습니다.', NULL, '잇몸 퇴축,치주,심미', 3, 0),
('bone-loss', '치조골 흡수', 'Alveolar Bone Loss', '치주', '잇몸병으로 턱뼈가 녹는 현상', '치주질환이 진행되면 잇몸 아래 턱뼈(치조골)가 점차 녹아 없어지는 현상입니다. 치아가 흔들리고 결국 빠지게 되는 주요 원인입니다. X-ray로 확인 가능합니다.', NULL, '치주염,치조골,임플란트', 2, 0),
('probing-depth', '치주낭 깊이', 'Probing Depth', '치주', '잇몸 속 주머니의 깊이 측정', '치주 탐침으로 잇몸과 치아 사이 틈(치주낭)의 깊이를 측정하는 것입니다. 정상은 1~3mm이며, 4mm 이상이면 치주질환을 의심합니다. 깊을수록 질환이 진행된 상태입니다.', NULL, '치주낭,잇몸,치주염', 2, 0),
('chlorhexidine', '클로르헥시딘', 'Chlorhexidine', '치주', '강력한 구강 소독 양치액', '넓은 범위의 세균에 효과적인 구강 소독제입니다. 치주 수술 후, 임플란트 수술 후, 잇몸 치료 후 2주간 사용합니다. 장기간 사용 시 착색이 생길 수 있습니다.', NULL, '소독,잇몸,양치', 2, 0),
('laser-therapy', '레이저 치주치료', 'Laser Periodontal Therapy', '치주', '레이저를 이용한 잇몸 치료', '치주낭 내부에 레이저를 조사하여 감염 조직과 세균을 제거하는 최소 침습 치료입니다. 출혈이 적고, 치유가 빠르며, 전통적 치주 수술보다 환자 불편감이 적습니다.', NULL, '잇몸,치주,레이저', 2, 0);

-- ===== 소아/예방 추가 (8개) =====
INSERT OR IGNORE INTO dictionary (slug, term_ko, term_en, category, summary, description, related_treatment, related_terms, difficulty, is_featured) VALUES
('baby-tooth', '유치 (젖니)', 'Baby Tooth (Deciduous Tooth)', '소아', '처음 나는 첫 번째 치아', '생후 6개월경부터 나기 시작하여 총 20개가 나는 첫 번째 치아입니다. 6~12세 사이에 영구치로 교체됩니다. 유치도 충치 관리가 중요하며, 영구치 건강에 직접 영향을 줍니다.', NULL, '영구치,충치,소아치과', 1, 0),
('permanent-tooth', '영구치', 'Permanent Tooth', '소아', '유치 이후 나는 두 번째 치아', '유치가 빠진 후 나오는 성인 치아로, 총 28~32개(사랑니 포함)입니다. 한번 손상되면 다시 자라지 않으므로, 평생 관리가 필요합니다.', NULL, '유치,사랑니,치아', 1, 0),
('eruption', '치아 맹출', 'Tooth Eruption', '소아', '치아가 잇몸을 뚫고 나오는 것', '턱뼈 안에서 발육 중인 치아가 잇몸을 뚫고 구강 내로 나오는 과정입니다. 유치는 생후 6개월, 영구치는 만 6세부터 시작됩니다. 맹출 순서와 시기는 개인차가 있습니다.', NULL, '유치,영구치,소아치과', 1, 0),
('pulpotomy', '치수 절단술', 'Pulpotomy', '소아', '유치의 감염된 신경 일부만 제거하는 치료', '유치에 충치가 깊어 신경까지 노출되었을 때, 감염된 부분만 제거하고 약제로 치수를 보호하는 치료입니다. 유치의 수명을 연장하여 영구치가 정상적으로 나올 수 있게 합니다.', NULL, '유치,신경치료,소아치과', 2, 0),
('stainless-steel-crown', 'SSC (소아 크라운)', 'Stainless Steel Crown', '소아', '유치에 씌우는 스테인리스 기성 크라운', '충치가 심한 유치에 씌우는 기성품 금속 크라운입니다. 당일 치료가 가능하고, 유치가 빠질 때까지 훌륭한 보호를 제공합니다. 어금니에 주로 사용됩니다.', NULL, '유치,크라운,소아치과', 2, 0),
('tongue-tie', '설소대 단축증', 'Tongue-Tie (Ankyloglossia)', '소아', '혀 아래 소대가 짧아 혀 움직임이 제한되는 상태', '혀 아래 연결 띠(설소대)가 짧거나 두꺼워 혀를 충분히 움직이지 못하는 상태입니다. 수유 장애, 발음 문제를 일으킬 수 있으며, 간단한 절개로 치료합니다.', NULL, '소대 절제술,발음,수유', 1, 0),
('thumb-sucking', '손가락 빨기', 'Thumb Sucking', '소아', '유아기 손가락 빨기 습관', '유아기에 흔한 구강 습관으로, 4세 이후에도 계속되면 앞니 돌출, 개방교합 등 부정교합을 유발할 수 있습니다. 습관 차단 장치나 행동 교정으로 치료합니다.', NULL, '부정교합,개방교합,소아', 1, 0),
('pediatric-sedation', '소아 진정 치료', 'Pediatric Sedation', '소아', '어린이의 치과 공포를 줄이는 진정 치료', '치과 치료를 두려워하거나 협조가 어려운 어린이에게 안전한 진정제를 투여하여 편안한 상태에서 치료하는 방법입니다. 웃음 가스(아산화질소)가 대표적입니다.', NULL, '소아치과,마취,아산화질소', 2, 0);

-- ===== 장비/영상 추가 (12개) =====
INSERT OR IGNORE INTO dictionary (slug, term_ko, term_en, category, summary, description, related_treatment, related_terms, difficulty, is_featured) VALUES
('panoramic-xray', '파노라마 X-ray', 'Panoramic Radiograph', '장비', '턱 전체를 한 장에 촬영하는 X선 사진', '위아래 턱뼈와 모든 치아를 한 장의 사진으로 촬영하는 기본 치과 촬영법입니다. 매복치, 치조골 상태, 신경관 위치, 전체적인 치아 배열 등을 한눈에 파악할 수 있습니다.', NULL, 'X-ray,진단,CBCT', 1, 0),
('periapical-xray', '치근단 X-ray', 'Periapical Radiograph', '장비', '개별 치아를 정밀 촬영하는 X선 사진', '특정 치아 2~3개와 그 주변 뼈를 정밀하게 촬영하는 X선입니다. 충치 깊이, 신경치료 상태, 치근단 병소 등 세밀한 진단에 사용합니다.', NULL, 'X-ray,진단,충치', 1, 0),
('intraoral-scanner', '구강 스캐너', 'Intraoral Scanner', '장비', '입안을 3D로 스캔하는 디지털 장비', '기존의 불편한 본뜨기(인상채득) 대신, 카메라로 입안을 스캔하여 정밀한 3D 디지털 데이터를 획득하는 장비입니다. CEREC, 인비절라인 등 디지털 치료의 핵심 장비입니다.', NULL, 'CEREC,인비절라인,디지털', 2, 1),
('autoclave', '오토클레이브', 'Autoclave', '장비', '고압 증기 멸균 장비', '121°C 이상의 고압 증기로 치과 기구를 완전히 멸균하는 장비입니다. 모든 세균, 바이러스, 포자까지 사멸시켜 교차 감염을 방지합니다. 감염 관리의 핵심 장비입니다.', NULL, '멸균,감염 관리,소독', 1, 0),
('dental-laser', '치과용 레이저', 'Dental Laser', '장비', '다양한 치과 시술에 사용하는 레이저 장비', '연조직(잇몸) 절개, 충치 제거, 잇몸 치료, 미백 등에 활용되는 레이저 장비입니다. 출혈이 적고, 통증이 덜하며, 치유가 빠른 장점이 있습니다.', NULL, '잇몸 성형,치주치료,레이저', 2, 0),
('dental-microscope', '치과용 현미경', 'Dental Microscope', '장비', '미세한 부위를 확대하여 치료하는 현미경', '치아 내부를 최대 25배까지 확대하여 볼 수 있는 수술용 현미경입니다. 신경치료, 미세 수술 등에서 정밀한 시야를 확보하여 치료 성공률을 높입니다.', NULL, '신경치료,미세수술,정밀', 2, 0),
('air-shower', '에어 샤워', 'Air Shower', '장비', '진료실 진입 전 먼지를 제거하는 공기 정화 장치', '수술실이나 진료실 진입 전 강한 공기를 분사하여 의복에 묻은 먼지, 세균 등을 제거하는 감염 관리 장치입니다. 대학병원급 감염 관리 시스템의 핵심 장비입니다.', NULL, '감염 관리,멸균,수술실', 2, 0),
('dental-unit-chair', '치과 유닛 체어', 'Dental Unit Chair', '장비', '환자가 앉는 치과 진료 의자', '환자가 앉아 진료받는 복합 장비로, 의자뿐 아니라 핸드피스, 에어/물 분사기, 흡인기, 조명 등이 통합되어 있습니다. 현대 치과 유닛은 환자 편안함과 의사의 인체공학을 모두 고려합니다.', NULL, '진료,장비,핸드피스', 1, 0),
('handpiece', '핸드피스', 'Dental Handpiece', '장비', '치아를 깎는 고속/저속 회전 기구', '치아를 삭제, 연마하는 데 사용하는 회전 기구입니다. 고속 핸드피스(터빈)는 충치 제거·치아 삭제에, 저속 핸드피스는 연마·뿌리 치료에 사용합니다.', NULL, '장비,충치,삭제', 1, 0),
('suction', '석션 (흡인기)', 'Dental Suction', '장비', '구강 내 물과 타액을 흡입하는 장치', '치료 중 발생하는 물, 타액, 혈액, 분진 등을 빨아들이는 장치입니다. 환자의 편안함과 시야 확보, 감염 관리에 필수적인 장비입니다.', NULL, '장비,진료,감염 관리', 1, 0),
('digital-impression', '디지털 인상', 'Digital Impression', '장비', '구강 스캐너로 치아 형태를 기록하는 방법', '기존 실리콘 인상재 대신 구강 스캐너로 치아와 잇몸의 3D 형태를 디지털로 기록하는 방법입니다. 환자 불편감이 없고, 정확도가 높으며, 데이터 전송이 즉시 가능합니다.', NULL, '구강 스캐너,CEREC,보철', 2, 0),
('apex-locator', '근관 길이 측정기', 'Apex Locator', '장비', '신경치료 시 치아 뿌리 끝까지의 길이를 측정하는 장비', '전기적 임피던스를 이용하여 치아 뿌리 끝(근첨)까지의 정확한 길이를 측정하는 장비입니다. X선 촬영 횟수를 줄이고, 신경치료의 정확도를 높입니다.', NULL, '신경치료,근관,정밀', 2, 0);

-- ===== 해부학 추가 (10개) =====
INSERT OR IGNORE INTO dictionary (slug, term_ko, term_en, category, summary, description, related_treatment, related_terms, difficulty, is_featured) VALUES
('maxilla', '상악 (윗턱)', 'Maxilla', '해부학', '위쪽 턱뼈', '얼굴 중앙부를 구성하는 뼈로, 윗니를 지지합니다. 상악동(부비강)이 있어 윗턱 어금니 부위의 뼈가 얇을 수 있으며, 이 경우 상악동 거상술이 필요할 수 있습니다.', NULL, '상악동,임플란트,뼈이식', 2, 0),
('mandible', '하악 (아래턱)', 'Mandible', '해부학', '아래쪽 턱뼈', '얼굴에서 유일하게 움직이는 뼈로, 아랫니를 지지하고 저작(씹기) 운동을 담당합니다. 하치조신경이 지나가므로 임플란트 수술 시 주의가 필요합니다.', NULL, '하치조신경,임플란트,저작', 2, 0),
('inferior-alveolar-nerve', '하치조신경', 'Inferior Alveolar Nerve', '해부학', '아래턱 속을 지나가는 감각 신경', '하악골 내부를 관통하는 신경으로, 아랫니와 턱, 아랫입술의 감각을 담당합니다. 하악 임플란트나 사랑니 발치 시 이 신경을 손상하지 않도록 주의해야 합니다.', NULL, '임플란트,사랑니,신경 손상', 3, 0),
('maxillary-sinus', '상악동', 'Maxillary Sinus', '해부학', '윗턱 어금니 위의 빈 공간', '광대뼈 안쪽에 있는 부비강(공기가 차 있는 빈 공간)입니다. 윗턱 어금니 뿌리와 가까이 있어, 뼈가 얇은 경우 임플란트 시 상악동 거상술이 필요합니다.', NULL, '상악동 거상술,임플란트,부비강', 2, 0),
('temporomandibular-joint', '측두하악관절 (턱관절)', 'Temporomandibular Joint', '해부학', '턱뼈와 두개골을 연결하는 관절', '귀 앞쪽에 위치하며 입을 벌리고 닫을 때 사용하는 관절입니다. 이 관절에 문제가 생기면 소리, 통증, 개구 제한 등 턱관절 장애가 나타납니다.', NULL, '턱관절 장애,교합,이갈이', 2, 0),
('oral-mucosa', '구강 점막', 'Oral Mucosa', '해부학', '입안을 감싸는 점막 조직', '입안 전체를 덮고 있는 촉촉한 점막 조직입니다. 볼, 입술 안쪽, 혀, 잇몸, 입천장 등을 포함합니다. 구내염, 백반증, 구강암 등의 질환이 발생할 수 있습니다.', NULL, '구내염,구강암,점막', 1, 0),
('palate', '구개 (입천장)', 'Palate', '해부학', '입의 천장 부분', '구강의 윗부분으로, 앞쪽의 경구개(딱딱한 부분)와 뒤쪽의 연구개(부드러운 부분)로 나뉩니다. 잇몸 이식 시 경구개에서 조직을 채취하며, 의치(틀니)가 닿는 부위이기도 합니다.', NULL, '잇몸 이식,틀니,해부학', 2, 0),
('salivary-gland', '타액선 (침샘)', 'Salivary Gland', '해부학', '침을 분비하는 샘', '구강에 침(타액)을 분비하는 기관으로, 이하선, 악하선, 설하선의 3대 타액선과 수많은 소타액선이 있습니다. 구강 건조증은 타액 분비 감소로 충치와 잇몸병 위험을 높입니다.', NULL, '구강건조증,충치,잇몸', 2, 0),
('occlusion', '교합', 'Occlusion', '해부학', '윗니와 아랫니가 맞물리는 관계', '위아래 치아가 서로 만나는 관계를 말합니다. 정상 교합, 부정교합, 외상성 교합 등이 있으며, 교합이 나쁘면 턱관절 장애, 치아 마모, 두통 등이 발생할 수 있습니다.', NULL, '부정교합,턱관절,교정', 2, 0),
('frenum', '소대', 'Frenum', '해부학', '입술이나 혀를 잇몸에 연결하는 조직 띠', '입술 안쪽과 잇몸(순소대), 혀 아래와 구강 바닥(설소대)을 연결하는 얇은 조직 띠입니다. 너무 짧거나 두꺼우면 기능 장애를 일으켜 절제가 필요할 수 있습니다.', NULL, '소대 절제술,설소대,순소대', 1, 0);

-- ===== 보험/행정 추가 (10개) =====
INSERT OR IGNORE INTO dictionary (slug, term_ko, term_en, category, summary, description, related_treatment, related_terms, difficulty, is_featured) VALUES
('health-insurance', '건강보험', 'National Health Insurance', '보험', '국민건강보험 급여 치과 진료', '대한민국 건강보험이 적용되는 치과 진료 항목입니다. 스케일링(연 1회), 레진 충전(12세 이하), 치석 제거, 발치, 신경치료, 65세 이상 임플란트(2개) 등이 급여 대상입니다.', NULL, '스케일링,임플란트 보험,급여', 1, 1),
('copayment', '본인부담금', 'Copayment', '보험', '환자가 직접 부담하는 치료비 비율', '건강보험 적용 시 전체 치료비 중 환자가 부담하는 금액 비율입니다. 일반 치과는 30%, 임플란트 보험은 30%, 스케일링은 무료~수천원 수준입니다.', NULL, '건강보험,급여,치료비', 1, 0),
('non-covered', '비급여', 'Non-Covered Treatment', '보험', '건강보험이 적용되지 않는 치료', '건강보험 급여 대상이 아닌 치과 치료입니다. 교정, 미백, 라미네이트, 임플란트(65세 미만), 세라믹 보철 등이 비급여에 해당하며, 전액 환자 부담입니다.', NULL, '건강보험,치료비,비급여', 1, 0),
('dental-chart', '치아 차트', 'Dental Chart', '보험', '각 치아에 번호를 부여한 도표', '국제적으로 각 치아에 2자리 번호를 부여하는 체계(FDI 표기법)입니다. 첫째 자리는 사분면(1~4), 둘째 자리는 치아 번호(1~8)입니다. 예: 16번 = 오른쪽 위 첫째 어금니.', NULL, '진단,기록,FDI', 1, 0),
('informed-consent', '동의서', 'Informed Consent', '보험', '치료 전 환자에게 설명하고 동의를 받는 절차', '치료의 목적, 방법, 예상 결과, 가능한 합병증 등을 환자에게 충분히 설명하고, 환자가 이해한 후 서면으로 동의하는 법적 절차입니다.', NULL, '치료계획,환자권리,법적', 1, 0),
('treatment-plan', '치료 계획서', 'Treatment Plan', '보험', '체계적인 치료 순서와 내용을 정리한 문서', '환자의 구강 상태를 진단하고, 필요한 치료를 순서대로 정리한 계획서입니다. 치료 내용, 기간, 예상 비용, 대안 등을 포함하며, 환자와 상의하여 최종 결정합니다.', NULL, '진단,상담,치료비', 1, 0),
('dental-recall', '리콜 (정기 검진)', 'Dental Recall', '보험', '정기적으로 치과를 방문하는 검진 시스템', '치료 완료 후 3~6개월마다 정기적으로 내원하여 구강 상태를 점검받는 시스템입니다. 조기 발견·조기 치료로 큰 치료를 예방하며, 스케일링도 함께 시행합니다.', NULL, '스케일링,예방,정기검진', 1, 0),
('medical-certificate', '진단서', 'Medical Certificate', '보험', '의사가 발행하는 공식 진단 문서', '환자의 질환명, 치료 내용, 향후 치료 계획 등을 의사가 공식적으로 기재한 문서입니다. 보험 청구, 학교·직장 제출, 법적 증거 등에 사용됩니다.', NULL, '진단,보험,서류', 1, 0),
('dental-fee', '치과 수가', 'Dental Fee Schedule', '보험', '건강보험 행위별 수가 기준', '건강보험심사평가원에서 정한 치과 치료 행위별 가격 기준입니다. 급여 항목은 이 수가에 따라 청구되며, 매년 수가 인상률이 결정됩니다.', NULL, '건강보험,급여,치료비', 2, 0),
('preventive-care', '예방 진료', 'Preventive Dental Care', '보험', '질환 발생 전 미리 관리하는 치과 진료', '충치와 잇몸 질환이 발생하기 전에 예방하는 진료입니다. 정기 검진, 스케일링, 불소 도포, 실란트, 올바른 칫솔질 교육 등이 포함됩니다. 치료보다 예방이 경제적입니다.', NULL, '스케일링,불소,실란트', 1, 0);
